const cachedHandler = (event: KeyboardEvent) => {
  const code = getEventCode(event)
  if (code === EVENT_CODE.esc) {
    registeredEscapeHandlers.forEach((registeredHandler) =>
      registeredHandler(event)
    )
  }
}

export const useEscapeKeydown = (handler: (e: KeyboardEvent) => void) => {
  onMounted(() => {
    if (registeredEscapeHandlers.length === 0) {
      document.addEventListener('keydown', cachedHandler)
    }
    if (isClient) registeredEscapeHandlers.push(handler)
  })

  onBeforeUnmount(() => {
    registeredEscapeHandlers = registeredEscapeHandlers.filter(
      (registeredHandler) => registeredHandler !== handler
    )
    if (registeredEscapeHandlers.length === 0) {
      if (isClient) document.removeEventListener('keydown', cachedHandler)
    }
  })
}

import type { ComputedRef } from 'vue'
import type { ThemeCommonVars } from '../_styles/common'
import type { CustomThemeCommonVars } from '../config-provider'
import { computed, inject } from 'vue'
import { commonLight } from '../_styles/common'
import { configProviderInjectionKey } from '../config-provider/src/context'

export function useThemeVars(): ComputedRef<
  ThemeCommonVars & CustomThemeCommonVars
> {
  const configProviderInjection = inject(configProviderInjectionKey, null)
  return computed(() => {
    if (configProviderInjection === null)
      return commonLight
    const {
      mergedThemeRef: { value: mergedTheme },
      mergedThemeOverridesRef: { value: mergedThemeOverrides }
    } = configProviderInjection
    const currentThemeVars = mergedTheme?.common || commonLight
    if (mergedThemeOverrides?.common) {
      return Object.assign({}, currentThemeVars, mergedThemeOverrides.common)
    }
    else {
      return currentThemeVars
    }
  })
}

export const paginationMixin = extend({
  props,
  computed: {
    localPaging() {
      return this.hasProvider ? !!this.noProviderPaging : true
    },
    paginatedItems() {
      const { sortedItems, filteredItems, localItems } = safeVueInstance(this)
      let items = sortedItems || filteredItems || localItems || []
      const currentPage = mathMax(toInteger(this.currentPage, 1), 1)
      const perPage = mathMax(toInteger(this.perPage, 0), 0)
      // Apply local pagination
      if (this.localPaging && perPage) {
        // Grab the current page of data (which may be past filtered items limit)
        items = items.slice((currentPage - 1) * perPage, currentPage * perPage)
      }
      // Return the items to display in the table
      return items
    }
  }
})

const updateTabElementsArray = () => {
  const tabElements = flattenFragments(slots.default?.({}) ?? [])
  tabElementsArray.value = (Array.isArray(tabElements) ? tabElements : [tabElements]).filter(
    (tab) => tab.type === BTab
  )
  // only get the ids once in setup context
  if (initialIds.value.length === 0) {
    // we need to get the ids of the tabs before they are registered. After that we use the internalId for the tabpane
    initialIds.value = tabElementsArray.value.map((tab) =>
      unref(useId(() => tab.props?.id, 'tabpane'))
    )
    // Check if any tab has an explicit ID
    hasExplicitIds.value = tabElementsArray.value.some((tab) => tab.props?.id !== undefined)
  }
  isChildActive.value = tabElementsArray.value.some(
    (tab) => tab.props?.active !== undefined && tab.props?.active !== false
  )
}

const handleUnmount = (
  el: Element,
  binding: DirectiveBinding<string | readonly string[] | undefined>,
  vnode: VNode
) => {
  // Determine targets
  const targets = getTargets(binding, el)
  if (targets.length === 0) return
  const provides = findProvides(binding, vnode, true)
  const showHideMap =
    (provides as Record<symbol, RegisterShowHideValue>)[showHideRegistryKey]?.values ?? null

  targets.forEach((targetId) => {
    const showHide = getActiveShowHide(showHideMap, targetId)
    if (!showHide) {
      return
    }
    // Pass clean=true to let the composable handle cleanup of aria-expanded and classes
    showHide.unregisterTrigger('click', el, true)
  })

  // Only remove what the directive manages (aria-controls)
  // aria-expanded and classes are managed by useShowHide composable
  el.removeAttribute('aria-controls')
  delete (el as HTMLElement).dataset.bvtoggle
}

const initInstance = (
  props: any,
  container: HTMLElement,
  appContext: AppContext | null = null
) => {
  const vnode = createVNode(
    MessageBoxConstructor,
    props,
    isFunction(props.message) || isVNode(props.message)
      ? {
          default: isFunction(props.message)
            ? () =>
                props.message({
                  confirm: handleAction(vnode, 'confirm'),
                  cancel: handleAction(vnode, 'cancel'),
                  close: handleAction(vnode, 'close'),
                })
            : () => props.message,
        }
      : null
  )
  vnode.appContext = appContext
  render(vnode, container)
  getAppendToElement(props).appendChild(container.firstElementChild!)
  return vnode.component
}

